30	
31	const (
32		AuthViaLocalPassword AuthSource = iota // Local database password authentication
33		AuthViaLDAP                            // LDAP directory authentication
34		AuthViaToken                           // JWT or API token authentication
35		AuthViaOIDC                            // OpenID Connect authentication
36		AuthViaAll                             // Accepts any auth source (special case)
37	)
