47	// User represents a ClusterCockpit user account with authentication and authorization information.
48	//
49	// Users are authenticated via various sources (local, LDAP, OIDC) and assigned roles that
50	// determine access levels. Projects lists the HPC projects/accounts the user has access to.
51	type User struct {
52		Username   string     `json:"username"`   // Unique username
53		Password   string     `json:"-"`          // Password hash (never serialized to JSON)
54		Name       string     `json:"name"`       // Full display name
55		Email      string     `json:"email"`      // Email address
56		Roles      []string   `json:"roles"`      // Assigned role names
57		Projects   []string   `json:"projects"`   // Authorized project/account names
58		AuthType   AuthType   `json:"authType"`   // How the user authenticated
59		AuthSource AuthSource `json:"authSource"` // Which system authenticated the user
60	}
