67	// GetRoleString returns the lowercase string representation of a Role enum value.
68	func GetRoleString(roleInt Role) string {
69		return [6]string{"anonymous", "api", "user", "manager", "support", "admin"}[roleInt]
70	}
71	
72	func getRoleEnum(roleStr string) Role {
73		switch strings.ToLower(roleStr) {
74		case "admin":
75			return RoleAdmin
76		case "support":
77			return RoleSupport
78		case "manager":
79			return RoleManager
80		case "user":
81			return RoleUser
82		case "api":
83			return RoleAPI
84		case "anonymous":
85			return RoleAnonymous
86		default:
87			return RoleError
88		}
89	}
90	
91	// IsValidRole reports whether the given string corresponds to a known role name.
92	func IsValidRole(role string) bool {
93		return getRoleEnum(role) != RoleError
94	}
95	
96	// HasValidRole checks whether the user has the specified role and whether the role string is valid.
97	// Returns hasRole=true if the user has the role, and isValid=true if the role name is recognized.
98	func (u *User) HasValidRole(role string) (hasRole bool, isValid bool) {
99		if IsValidRole(role) {
100			if slices.Contains(u.Roles, role) {
101				return true, true
102			}
103			return false, true
104		}
105		return false, false
106	}
107	
108	// HasRole reports whether the user has the specified role.
109	func (u *User) HasRole(role Role) bool {
110		return slices.Contains(u.Roles, GetRoleString(role))
111	}
112	
113	// HasAnyRole reports whether the user has at least one of the given roles.
114	func (u *User) HasAnyRole(queryroles []Role) bool {
115		for _, ur := range u.Roles {
116			for _, qr := range queryroles {
117				if ur == GetRoleString(qr) {
118					return true
119				}
120			}
121		}
122		return false
123	}
124	
125	// HasAllRoles reports whether the user has every one of the given roles.
126	func (u *User) HasAllRoles(queryroles []Role) bool {
127		target := len(queryroles)
128		matches := 0
129		for _, ur := range u.Roles {
130			for _, qr := range queryroles {
131				if ur == GetRoleString(qr) {
132					matches += 1
133					break
134				}
135			}
136		}
137	
138		if matches == target {
139			return true
140		} else {
141			return false
142		}
143	}
144	
145	// HasNotRoles reports whether the user has none of the given roles.
146	func (u *User) HasNotRoles(queryroles []Role) bool {
147		matches := 0
148		for _, ur := range u.Roles {
149			for _, qr := range queryroles {
150				if ur == GetRoleString(qr) {
151					matches += 1
152					break
153				}
154			}
155		}
156	
157		if matches == 0 {
158			return true
159		} else {
160			return false
161		}
162	}
