164	// GetValidRoles returns the list of assignable role names. Only admins may call this;
165	// returns an error if the user does not have the Admin role.
166	func GetValidRoles(user *User) ([]string, error) {
167		var vals []string
168		if user.HasRole(RoleAdmin) {
169			for i := RoleAPI; i < RoleError; i++ {
170				vals = append(vals, GetRoleString(i))
171			}
172			return vals, nil
173		}
174	
175		return vals, fmt.Errorf("%s: only admins are allowed to fetch a list of roles", user.Username)
176	}
