178	// GetValidRolesMap returns a map of role names to Role enum values. Requires any
179	// authenticated (non-anonymous) user; returns an error for anonymous users.
180	func GetValidRolesMap(user *User) (map[string]Role, error) {
181		named := make(map[string]Role)
182		if user.HasNotRoles([]Role{RoleAnonymous}) {
183			for i := RoleAPI; i < RoleError; i++ {
184				named[GetRoleString(i)] = i
185			}
186			return named, nil
187		}
188		return named, fmt.Errorf("only known users are allowed to fetch a list of roles")
189	}
