196		} else if u.HasRole(RoleSupport) {
197			return RoleSupport
198		} else if u.HasRole(RoleManager) {
199			return RoleManager
200		} else if u.HasRole(RoleUser) {
201			return RoleUser
202		} else if u.HasRole(RoleAPI) {
203			return RoleAPI
204		} else if u.HasRole(RoleAnonymous) {
205			return RoleAnonymous
206		} else {
207			return RoleError
208		}
